import { useEffect, useState } from 'react';
import api from '../api/client';

export default function ClosedTickets() {
  const [tickets, setTickets] = useState([]);

  const loadClosedTickets = async () => {
    try {
      const res = await api.get('/tickets/', {
        params: { status: 'Closed' }
      });
      setTickets(res.data.results || []);
    } catch (err) {
      console.error(err);
      setTickets([]);
    }
  };

  const handleExport = async () => {
    try {
      const res = await api.get('/tickets/export_excel/', {
        params: { status: 'Closed' },
        responseType: 'blob',
      });

      const url = window.URL.createObjectURL(new Blob([res.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', 'closed_tickets.xlsx');
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    loadClosedTickets();
  }, []);

  return (
    <div className="card mt-4">
      <div className="card-body">
        <div className="d-flex justify-content-between mb-3">
          <h4>Closed Tickets</h4>
          <button className="btn btn-success" onClick={handleExport}>
            Export Excel
          </button>
        </div>

        <div className="table-responsive">
          <table className="table table-bordered table-striped">
            <thead>
              <tr>
                <th>Ticket ID</th>
                <th>Department</th>
                <th>Division</th>
                <th>Module</th>
                <th>Submodule</th>
                <th>Subject</th>
                <th>Status</th>
                <th>Closed Date</th>
              </tr>
            </thead>
            <tbody>
              {tickets.length ? (
                tickets.map((ticket) => (
                  <tr key={ticket.id}>
                    <td>{ticket.ticket_id}</td>
                    <td>{ticket.department_name || ''}</td>
                    <td>{ticket.division_name || ''}</td>
                    <td>{ticket.module_name || ''}</td>
                    <td>{ticket.submodule_name || ''}</td>
                    <td>{ticket.subject}</td>
                    <td>{ticket.status}</td>
                    <td>{ticket.closed_at ? new Date(ticket.closed_at).toLocaleString() : ''}</td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="8">No closed tickets available</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
